  interpretacao_funcional = excluded.interpretacao_funcional,
  nutrientes = excluded.nutrientes,
  sinais_alto = excluded.sinais_alto,
  sinais_baixo = excluded.sinais_baixo,
  estrategia_alto = excluded.estrategia_alto,
  estrategia_baixo = excluded.estrategia_baixo,
  atencao = excluded.atencao,
  referencias = excluded.referencias,
  updated_at = now();

notify pgrst, 'reload schema';
